import{j as e}from"./vendor-Dh_dlHsl.js";import{C as t,A as n,N as s,E as a,P as i,W as o}from"./subject-01-thinking-in-agents-BIrOrpH9.js";const T={id:"teams-coordination",title:"Teams and Coordination",description:"From solo agents to coordinated squads — team architecture, communication patterns, and swarm intelligence.",icon:"👥",colorHex:"#a855f7",difficulty:"advanced",estimatedHours:12,prerequisites:["delegation"],chapters:[{id:"c1-team-architecture",title:"Team Architecture",description:"Roles, structure, and lifecycle of agent teams.",difficulty:"advanced",estimatedMinutes:80,sections:[{id:"s1-what-is-team",title:"What Is an Agent Team",description:"Roles, structure, and purpose — why teams exist in multi-agent systems.",difficulty:"intermediate",readingMinutes:10},{id:"s2-team-lead",title:"The Team Lead",description:"Orchestration and authority — the agent that coordinates the others.",difficulty:"advanced",readingMinutes:12},{id:"s3-teammates",title:"Teammates",description:"Parallel workers with complementary skills — the power of specialization.",difficulty:"advanced",readingMinutes:10},{id:"s4-team-lifecycle",title:"Team Formation and Dissolution",description:"Creating teams on demand and cleaning them up when done.",difficulty:"advanced",readingMinutes:10}]},{id:"c2-communication",title:"Communication Patterns",description:"How agents talk to each other — messaging, broadcasting, and approval flows.",difficulty:"advanced",estimatedMinutes:100,sections:[{id:"s1-point-to-point",title:"Point-to-Point",description:"Direct agent-to-agent messages — the simplest communication pattern.",difficulty:"advanced",readingMinutes:10},{id:"s2-broadcast",title:"Broadcast",description:"Announcing to all team members — one message, many recipients.",difficulty:"advanced",readingMinutes:10},{id:"s3-async-mailboxes",title:"Asynchronous Mailboxes",description:"Messages that wait until read — decoupling sender and receiver in time.",difficulty:"advanced",readingMinutes:12},{id:"s4-approval-flows",title:"Approval Flows",description:"Structured request-confirm-execute patterns — agents that ask permission.",difficulty:"advanced",readingMinutes:10},{id:"s5-shutdown-protocols",title:"Shutdown Protocols",description:"Coordinated graceful termination — winding down a team safely.",difficulty:"advanced",readingMinutes:10}]},{id:"c3-swarm",title:"Swarm Intelligence",description:"Many agents, one emergent goal — backends, identity, and conflict resolution.",difficulty:"advanced",estimatedMinutes:100,sections:[{id:"s1-what-is-swarm",title:"What Is a Swarm",description:"Many agents pursuing one emergent goal — collective intelligence in practice.",difficulty:"advanced",readingMinutes:10},{id:"s2-execution-backends",title:"Execution Backends",description:"Where agents actually run — in-process, terminal panes, and split windows.",difficulty:"advanced",readingMinutes:12},{id:"s3-identity-visibility",title:"Identity and Visibility",description:"Naming, coloring, and tracking agents — knowing who is doing what.",difficulty:"advanced",readingMinutes:10},{id:"s4-shared-state",title:"Shared State",description:"How swarm members stay in sync — shared memory and coordination primitives.",difficulty:"advanced",readingMinutes:12},{id:"s5-conflict-resolution",title:"Conflict Resolution",description:"When agents disagree — merging conflicting changes and resolving disputes.",difficulty:"advanced",readingMinutes:12}]}]};function r(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"What Is an Agent Team?"}),e.jsx("p",{children:'The term "multi-agent system" covers a wide range of configurations — from a simple orchestrator calling a single sub-agent to sprawling networks of dozens of specialised workers. An agent team is a specific and more structured arrangement: a persistent, coordinated group of agents with defined roles, shared goals, and explicit communication protocols. Understanding what makes a team distinct from an ad-hoc collection of agents is the foundation for designing one well.'}),e.jsx(t,{title:"Agent Team",number:"Concept 8.1",children:"An agent team is a group of agents with assigned roles, a shared objective, and coordination mechanisms that govern how they communicate and divide work. Unlike a loose collection of independently spawned sub-agents, a team has structure: there is typically a lead responsible for coordination, teammates with defined responsibilities, and agreed-upon protocols for passing information and resolving conflicts. Teams are designed to persist across multiple interactions rather than being assembled once for a single task."}),e.jsx("p",{children:'The distinction between "a group of agents" and "a team" is meaningful in practice. An unstructured group of agents doing similar work in parallel is a swarm — useful for embarrassingly parallel tasks but not for work requiring coordination and interdependence. A team is chosen when the task has sub-problems that depend on each other, when different components require different expertise, and when the combined output needs coherent integration rather than simple aggregation.'}),e.jsx(n,{title:"The Film Production Crew",children:"A film production crew is a team, not a crowd. The director, cinematographer, sound designer, and editor each have defined roles and responsibilities. They communicate through established protocols — dailies, production meetings, notes. Their work is interdependent: the editor cannot work until the cinematographer has shot, the sound designer needs the rough cut. The team's structure exists to manage those dependencies and ensure the final product is coherent, not a collection of disconnected pieces."}),e.jsx(s,{type:"note",title:"Teams vs Pipelines",children:"A pipeline is sequential — Agent A outputs to Agent B outputs to Agent C. A team is more network-like: members can communicate laterally, the lead can redirect work, and members can surface problems upstream. Teams are appropriate when the task requires adaptive coordination; pipelines are appropriate when the flow is fixed and predictable."}),e.jsx(a,{title:"Defining an Agent Team",exercises:[{id:"wit-1",difficulty:"beginner",question:"What are three structural properties that distinguish an agent team from a simple collection of parallel sub-agents? Give a concrete example of why each property matters.",hint:"Think about roles, communication, and shared goals.",solution:"(1) Defined roles: each team member has a specific responsibility, preventing overlap and gaps. Without this, two agents may both attempt the same sub-task while another is left uncovered. (2) Explicit communication protocols: team members pass information in agreed formats via agreed channels. Without this, outputs from one agent may be incompatible with what another needs. (3) Shared goal: all members are oriented toward the same outcome. Without a shared goal, agents optimise locally in ways that conflict at the system level."},{id:"wit-2",difficulty:"intermediate",question:"A product company wants to build an agent team to handle customer support escalations. Sketch the team structure: define the roles needed, what each role is responsible for, and one key dependency between roles.",hint:"Think about triage, domain expertise, resolution, and follow-up.",solution:"Roles: (1) Triage agent — reads the incoming ticket and routes it to the appropriate specialist. (2) Technical specialist agent — handles technical product issues. (3) Billing specialist agent — handles payment and subscription issues. (4) Resolution agent — drafts the final customer-facing response. Key dependency: the resolution agent cannot draft a response until the relevant specialist has produced a diagnosis or resolution recommendation. The triage agent's routing decision also determines which specialist is activated."},{id:"wit-3",difficulty:"advanced",question:"Under what conditions should you choose a team architecture over a simpler pipeline or a single orchestrator with multiple sub-agents? Identify at least three conditions and explain the reasoning behind each.",hint:"Think about when lateral communication, adaptive coordination, and persistent roles become necessary.",solution:"(1) The task requires lateral communication between workers (not just top-down orchestration) — a pipeline cannot support this; a team can. (2) The task recurs frequently enough that maintaining persistent, specialised roles is more efficient than assembling sub-agents from scratch each time. (3) Different sub-problems require materially different expertise and context — a single orchestrator with generic sub-agents produces lower quality than specialists. (4) The overall task must adapt mid-execution based on intermediate findings — a fixed pipeline cannot update its routing; a team with a lead can re-assign work dynamically."}]})]})}const j=Object.freeze(Object.defineProperty({__proto__:null,default:r},Symbol.toStringTag,{value:"Module"}));function l(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"The Team Lead"}),e.jsx("p",{children:"Every well-functioning team has a coordinator: someone who understands the overall goal, assigns work, tracks progress, and integrates results. In an agent team, this role is filled by the team lead. The team lead is not simply the most capable agent — it is the agent specifically designed for coordination, planning, and decision-making at the team level."}),e.jsx(t,{title:"The Team Lead Agent",number:"Concept 8.2",children:"The team lead is the coordinating agent responsible for decomposing the team's overall goal into sub-tasks, assigning those tasks to the appropriate teammates, monitoring progress, and integrating results into a coherent final output. The team lead does not typically do the specialised work itself — it directs, monitors, and synthesises. Its prompt is designed for planning and coordination rather than deep domain execution."}),e.jsx("p",{children:"The team lead occupies a unique position: it must understand enough about each teammate's domain to assign work intelligently, but it does not need to match any teammate's depth. It needs strong planning, task decomposition, and integration skills. These are distinct capabilities from domain expertise, and they should be reflected in how the team lead is configured and prompted."}),e.jsx(i,{title:"Lead for Coordination, Not Execution",number:"Principle 8.1",children:"A team lead that does most of the substantive work is not leading — it is hoarding. The team lead's comparative advantage is coordination: tracking the whole, managing dependencies, and synthesising across parts. When a team lead starts executing deep domain tasks, it sacrifices its coordination bandwidth. Design the team lead to delegate aggressively and focus on integration."}),e.jsx(o,{title:"The Bottleneck Lead",children:"If all communication between teammates must flow through the team lead, the lead becomes a bottleneck as team size grows. Design communication protocols that allow lateral communication between teammates where appropriate, reserving the lead for decisions and integrations that genuinely require the full-team view."}),e.jsx(a,{title:"Designing the Team Lead Role",exercises:[{id:"tl-1",difficulty:"beginner",question:"List five responsibilities that belong to the team lead and five that belong to specialist teammates. What is the key criterion that distinguishes lead responsibilities from teammate responsibilities?",hint:"Think about scope: whole-team view versus single-domain focus.",solution:"Lead responsibilities: (1) decomposing the goal into sub-tasks; (2) assigning tasks to the right specialist; (3) tracking task completion; (4) resolving conflicts between sub-results; (5) synthesising final output. Teammate responsibilities: (1) executing assigned tasks with domain depth; (2) reporting results in the agreed format; (3) flagging blockers within their scope; (4) following the constraints in their brief; (5) requesting clarification when the brief is ambiguous. Key criterion: lead responsibilities require the whole-team view; teammate responsibilities require only domain-specific depth."},{id:"tl-2",difficulty:"intermediate",question:"A team lead is working on a complex research task. At what point should it perform integration work itself versus spawning another specialist (e.g., a synthesis agent) to do it? What factors determine this?",hint:"Think about the synthesis task's complexity, the lead's available context, and specialisation value.",solution:"The lead should synthesise directly when: the integration is straightforward (combining three well-structured summaries into a report outline) and the lead has sufficient context budget. It should delegate synthesis to a specialist when: the synthesis requires domain depth the lead lacks; the synthesis task is long enough to exhaust the lead's available context; or the synthesis benefits from a clean, dedicated context rather than the lead's already-loaded state. The lead's primary resource is its attention and context window — protecting those is a valid reason to delegate even synthesis."},{id:"tl-3",difficulty:"advanced",question:"Design the team lead's state machine: the set of states it can be in during a team task, the events that trigger transitions, and the actions it takes in each state. Include at least five states.",hint:"Think about planning, dispatching, waiting, collecting, and concluding as starting states.",solution:"States: (1) Planning: receives goal, decomposes into tasks, assigns teammates. Transition to Dispatching when all tasks are assigned. (2) Dispatching: sends briefs to teammates. Transition to Monitoring when all briefs are sent. (3) Monitoring: tracks task completion, handles status updates. Transition to Collecting when all expected results arrive (or timeout). Transition to Replanning if a teammate reports failure. (4) Replanning: reassigns failed tasks or adjusts scope. Returns to Dispatching. (5) Collecting: receives and validates all results. Transition to Integrating. (6) Integrating: synthesises results into final output. Transition to Concluding. (7) Concluding: delivers output, releases resources, signals completion."}]})]})}const q=Object.freeze(Object.defineProperty({__proto__:null,default:l},Symbol.toStringTag,{value:"Module"}));function d(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Teammates: Roles and Responsibilities"}),e.jsx("p",{children:"In an agent team, teammates are the specialists who perform the actual domain work. Each teammate is designed for a specific class of tasks, has a prompt tuned to that domain, and is equipped with tools relevant to its role. Teammates are not interchangeable — their value comes precisely from being different from each other and from the team lead."}),e.jsx(t,{title:"Teammate Agents",number:"Concept 8.3",children:"Teammate agents are specialised agents in a team that execute assigned sub-tasks within their domain. Each teammate has a defined role (what kind of work it does), a capability set (what tools it can use), and a communication contract (how it reports results and raises blockers). Teammates receive work from the team lead, execute it independently, and return structured results. They do not direct the team's overall strategy."}),e.jsx("p",{children:"The depth of a teammate's specialisation is a design choice with trade-offs. Highly specialised teammates produce excellent output in their domain but are useless outside it. More generalist teammates can handle a wider range of tasks but may not match the quality of a true specialist. Most real teams benefit from a spectrum: a few deep specialists for the most critical domains and one or two generalists for tasks that don't fit neatly into a specialist's scope."}),e.jsx(n,{title:"The Jazz Ensemble",children:"Each musician in a jazz ensemble has a primary instrument and role. The bassist lays the harmonic foundation; the drummer keeps time; the soloist explores melodies. They are specialists in their roles. But they also listen to each other, respond to what others are playing, and adapt in real time. Specialisation does not mean isolation. Good teammates stay aware of the broader team context even while focused on their own part."}),e.jsx(s,{type:"tip",title:"Designing Teammate Interfaces",children:"A teammate's interface — the format of what it accepts and what it returns — is as important as the work it does internally. Design teammate interfaces to be simple, structured, and consistent. The team lead shouldn't need to parse prose outputs or infer missing fields. Each teammate should produce results in a form the lead can act on without interpretation."}),e.jsx(a,{title:"Designing Effective Teammates",exercises:[{id:"tm-1",difficulty:"beginner",question:"For a team tasked with producing a due diligence report on a startup, identify three distinct specialist teammates you would include. For each, state the role, one key tool they need, and the format of their output.",hint:"Think about financial, legal, and market angles separately.",solution:"(1) Financial analyst teammate: reviews financial statements and metrics. Tool: spreadsheet or data parsing tool. Output: JSON with key metrics (revenue growth, burn rate, runway). (2) Legal compliance teammate: checks for regulatory issues and pending litigation. Tool: legal database search. Output: structured list of identified risks with severity ratings. (3) Market researcher teammate: assesses market size and competitive landscape. Tool: web search and company database. Output: narrative summary with three key market findings and source citations."},{id:"tm-2",difficulty:"intermediate",question:"A teammate receives a brief it cannot complete — the data source it needs is unavailable. Describe the correct protocol for the teammate to follow. What should it communicate, to whom, and in what format?",hint:"Think about the difference between a failure and a blocker, and how the team lead uses this information.",solution:'The teammate should immediately report a blocker (not a failure) to the team lead. Blocker report format: { status: "blocked", task_id: "...", reason: "Data source unavailable", source_name: "...", suggested_alternatives: [...], estimated_delay: "unknown" }. It should not attempt to guess or fabricate data. The team lead can then decide whether to reassign the task, substitute an alternative source, or revise the plan. Reporting quickly and clearly — before wasting cycles on workarounds — is the correct protocol.'},{id:"tm-3",difficulty:"advanced",question:"Two teammates discover they need the same piece of information to complete their respective tasks. Neither has a tool to fetch it, and both are mid-task. How should this be handled, and what does this situation reveal about a gap in the team's design?",hint:"Think about shared dependencies and where they should be resolved in the team architecture.",solution:"Immediate handling: both teammates report the dependency to the team lead, which fetches or delegates the retrieval to a utility teammate and passes the result to both. The gap revealed: the team's briefing process failed to identify a shared dependency and pre-resolve it before dispatching the main tasks. In a well-designed team, the lead should map all task dependencies during planning and resolve shared inputs upfront — before any teammate that requires them is dispatched. Shared dependencies are the team lead's responsibility to surface, not the teammates'."}]})]})}const A=Object.freeze(Object.defineProperty({__proto__:null,default:d},Symbol.toStringTag,{value:"Module"}));function c(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Team Lifecycle"}),e.jsx("p",{children:"Agent teams are not static configurations — they go through distinct phases from formation to shutdown. Understanding the team lifecycle enables better design: each phase has different concerns, and problems that arise in production can often be traced to a phase that was handled poorly. A team that is assembled correctly but never properly shut down leaks resources just as surely as code with a memory leak."}),e.jsxs(t,{title:"Team Lifecycle Phases",number:"Concept 8.4",children:["An agent team passes through five phases: ",e.jsx("strong",{children:"formation"})," (the team is assembled, roles assigned, and communication channels established),",e.jsx("strong",{children:" briefing"})," (the goal is decomposed and each teammate receives their initial brief), ",e.jsx("strong",{children:"execution"})," (teammates work on their tasks, the lead monitors and coordinates), ",e.jsx("strong",{children:"integration"})," (results are collected, validated, and synthesised), and ",e.jsx("strong",{children:"shutdown"})," (all agents are gracefully terminated, resources released, and state persisted if needed). Skipping or rushing any phase creates problems in the phases that follow."]}),e.jsx("p",{children:"Formation deserves more attention than it typically receives. The decisions made at formation — which agents to include, how many, with what roles and tools — shape every subsequent phase. A team formed without thinking through the execution phase often discovers missing roles or wrong capability scoping only when a task fails. A brief formation and planning step pays dividends throughout execution."}),e.jsx(i,{title:"Design for the Full Lifecycle",number:"Principle 8.2",children:"Every team design should trace through all five lifecycle phases before deployment. Ask: how will this team form? How will the goal be decomposed? What happens if a teammate fails mid-execution? How will results be integrated? How will the team shut down cleanly? Gaps found in this exercise are far cheaper to fix in design than in production."}),e.jsx(s,{type:"tip",title:"Persistent vs Ephemeral Teams",children:"Some teams are ephemeral — assembled for one task, shut down when done. Others are persistent — kept alive across many tasks, with teammates that accumulate domain context over time. Persistent teams amortise formation costs and can develop richer internal coordination, but they also require lifecycle management across restarts, failures, and member replacement."}),e.jsx(a,{title:"Managing the Team Lifecycle",exercises:[{id:"tl-1",difficulty:"beginner",question:"For each of the five lifecycle phases (formation, briefing, execution, integration, shutdown), name one thing that can go wrong and one design practice that prevents it.",hint:"Think about the specific concerns of each phase separately.",solution:"Formation: wrong roles assembled → conduct a task-dependency analysis before choosing team composition. Briefing: briefs are too vague → use the four-element brief format (goal, context, constraints, output format) for every teammate. Execution: a teammate fails silently → require all teammates to report status at defined checkpoints. Integration: results are incompatible formats → specify output schemas in briefs and validate on receipt. Shutdown: agents left running after task completes → maintain a team ledger and verify all agents reach terminal state before the team is declared done."},{id:"tl-2",difficulty:"intermediate",question:"A persistent team is deployed to handle recurring tasks. Over time, one teammate's performance degrades. Describe the lifecycle events that should detect this, and how the team handles member replacement without interrupting service.",hint:"Think about monitoring, health checks, and hot-swapping a team member.",solution:"Detection: the team lead monitors output quality metrics for each teammate (e.g., result accuracy, task completion rate, error frequency). When a teammate's metrics cross a degradation threshold over a rolling window, the lead flags it for replacement. Replacement: (1) the lead stops assigning new tasks to the degraded teammate; (2) a new teammate instance is initialised with the same role configuration; (3) any in-progress tasks are re-assigned to the replacement; (4) the degraded teammate completes its current task or is cancelled cleanly; (5) the replacement enters the roster. The lead maintains continuity by never leaving a role unoccupied during the transition."},{id:"tl-3",difficulty:"advanced",question:"A team is partway through execution when the user cancels the overall task. Design the graceful shutdown sequence, accounting for: teammates mid-task, partial results that may have value, and external resources that must be released.",hint:"Prioritise resource release, then preserve anything worth keeping.",solution:"Shutdown sequence: (1) Team lead receives cancellation. Broadcasts stop-new-work signal to all teammates. (2) Teammates acknowledge and stop initiating new tool calls. They complete any tool call already in-flight if it will finish within 5 seconds; otherwise abandon. (3) Each teammate calls explicit release functions for any external resources it holds (open connections, locks, sessions). (4) Teammates send a partial-result package to the lead, even for incomplete work. Format: { task_id, completion_percentage, partial_findings: [...], resources_released: bool }. (5) Lead persists partial results to a recovery store with a task identifier, so work completed so far can be resumed or inspected. (6) Lead verifies all teammates report terminal status, force-terminates any that don't within the grace window. (7) Lead releases its own resources and marks task as cancelled-with-partial-results."}]})]})}const _=Object.freeze(Object.defineProperty({__proto__:null,default:c},Symbol.toStringTag,{value:"Module"}));function h(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Point-to-Point Communication"}),e.jsx("p",{children:"The most fundamental communication pattern in an agent team is direct, targeted messaging between two agents: one sender, one recipient, one message. This is point-to-point communication. It is simple, traceable, and easy to reason about — which makes it the right default for the majority of inter-agent exchanges in a well-designed team."}),e.jsx(t,{title:"Point-to-Point Communication",number:"Concept 8.5",children:"Point-to-point communication is a message sent from one specific agent to another, with a defined purpose: a task assignment, a status report, a result delivery, or a request for clarification. The sender knows who will receive the message; the recipient knows who sent it and why. This specificity makes point-to-point exchanges easy to audit, easy to attribute, and easy to replay for debugging. It is the backbone of structured team coordination."}),e.jsx("p",{children:"The simplicity of point-to-point communication is also its limitation. In a team with many members, maintaining direct channels between every pair of agents creates a dense network that is hard to manage. For small teams — typically fewer than six to eight agents — point-to-point communication is ideal. For larger teams, selective use of point-to-point for critical exchanges, combined with other patterns for broader announcements, produces better results."}),e.jsx(s,{type:"intuition",title:"Communication as a Design Constraint",children:"Think of each point-to-point channel as a named, purposeful connection. When designing a team, draw out the communication topology: who needs to talk to whom, and for what purpose? If the resulting diagram has more connections than you can easily trace, the team may be too large or too loosely structured for point-to-point to be the primary pattern."}),e.jsx(o,{title:"Informal Side Channels",children:"In human teams, informal communication channels emerge naturally — a quick corridor question, an unscheduled call. In agent teams, undocumented or ad-hoc communication bypasses the structured channels and creates messages that are invisible to the team lead and impossible to audit. Every agent communication should flow through a defined, logged channel."}),e.jsx(a,{title:"Point-to-Point Communication Design",exercises:[{id:"pp-1",difficulty:"beginner",question:"For a three-agent team (lead, researcher, writer), map out all the point-to-point channels that would exist. For each channel, name one message type that would flow across it.",hint:"Channels can be bidirectional — think about what flows in each direction.",solution:'Channels: (1) Lead → Researcher: task assignment ("research topic X, return key findings as a structured list"). (2) Researcher → Lead: result delivery ("here are five findings with sources"). (3) Lead → Writer: task assignment with context ("write a 500-word summary using these findings"). (4) Writer → Lead: completion report ("draft complete, attached for review"). (5) Researcher → Lead: blocker report ("source is unavailable, awaiting instructions"). Five directed channels, each with a distinct message type.'},{id:"pp-2",difficulty:"intermediate",question:"A team lead needs to send a task to a researcher and then later needs to query the status of that task. Design the message schemas for both the initial assignment and the status query. What fields are essential in each?",hint:"Think about what the recipient needs to act correctly on each message.",solution:'Task assignment schema: { type: "task_assignment", task_id: string, from: "lead", to: "researcher", goal: string, context: object, constraints: object, output_format: object, deadline: ISO-8601 }. Status query schema: { type: "status_query", task_id: string, from: "lead", to: "researcher", query_time: ISO-8601 }. Status response schema: { type: "status_response", task_id: string, from: "researcher", to: "lead", status: "in_progress"|"completed"|"blocked"|"failed", progress_note: string, estimated_completion: ISO-8601 | null }.'},{id:"pp-3",difficulty:"advanced",question:"Design a message routing layer for a six-agent team where all communication flows through a central message bus rather than direct agent-to-agent calls. What properties must the bus guarantee, and what metadata must every message carry?",hint:"Think about delivery guarantees, ordering, attribution, and observability.",solution:"Bus guarantees: (1) At-least-once delivery — no message silently dropped. (2) Ordering per channel — messages between the same sender-recipient pair arrive in send order. (3) Attribution — every message is signed with sender identity. (4) Persistence — messages are logged before delivery, enabling replay. Required metadata per message: { message_id: UUID, sent_at: timestamp, from_agent_id: string, to_agent_id: string, conversation_id: string (groups related messages), message_type: string, payload_schema_version: string }. The bus uses conversation_id to group related exchanges and enables the team lead to query the full history of any sub-task by conversation."}]})]})}const I=Object.freeze(Object.defineProperty({__proto__:null,default:h},Symbol.toStringTag,{value:"Module"}));function u(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Broadcast Communication"}),e.jsx("p",{children:"Not every message is meant for one agent. Some information needs to reach the entire team simultaneously: a change in the task's goal, a critical constraint that emerged mid-execution, a shutdown signal. For these situations, point-to-point communication is inefficient and error-prone — sending individual copies to each team member introduces ordering problems and the risk of some members receiving the message later than others. Broadcast communication solves this."}),e.jsx(t,{title:"Broadcast Communication",number:"Concept 8.6",children:"Broadcast communication is a message sent from one agent to all active team members simultaneously. It is used when information is relevant to every agent, when a change in the team's shared context needs to be propagated consistently, or when a signal must be received and acted on by all members at the same logical time. Broadcast messages are typically sent by the team lead and carry information that affects how all teammates should interpret or continue their current work."}),e.jsx("p",{children:'The key property of a broadcast is simultaneity: every recipient receives the same message, at the same time, without the lead having to maintain a list of individual channels. In practice, "same time" often means "before any member can take an action that the broadcast would affect" — the broadcast must arrive before any conflicting action, not necessarily at the exact same millisecond. Designing broadcast delivery to satisfy this ordering property is the core challenge.'}),e.jsx(s,{type:"tip",title:"When to Broadcast vs Point-to-Point",children:"Use broadcast for: team-wide context updates (the goal has changed), shutdown and pause signals, acknowledgement requests that all members must respond to, and shared state invalidations (cached data is now stale). Use point-to-point for everything else. Broadcasting routine task assignments clutters all agents' contexts with irrelevant information."}),e.jsx(o,{title:"Broadcast Overuse",children:"A team lead that broadcasts frequently creates cognitive load for all teammates, who must process every broadcast regardless of relevance to their current task. In agent terms, every broadcast consumes context window space in every teammate. Reserve broadcasts for genuinely team-wide information and send everything else point-to-point."}),e.jsx(a,{title:"Using Broadcast Communication Effectively",exercises:[{id:"bc-1",difficulty:"beginner",question:"For a five-person research team, list three events that should trigger a broadcast and three that should trigger a point-to-point message. Explain the difference.",hint:"Ask: does every team member need to know this immediately?",solution:"Broadcast-worthy: (1) The research scope has narrowed — all teammates must stop working on out-of-scope topics. (2) A new deadline has been imposed — all teammates need to re-prioritise. (3) A key source has been found that all researchers should use. Point-to-point: (1) Assigning a specific topic to one researcher. (2) Asking the writer for a status update. (3) Sending a tool credential to only the researcher who needs it."},{id:"bc-2",difficulty:"intermediate",question:'A team lead broadcasts an updated constraint ("all outputs must now be under 200 words"). Three teammates are mid-task with long outputs in progress. How should each teammate handle this broadcast, and what should they return?',hint:'Think about what "acknowledge" means for a broadcast and how teammates adapt in-progress work.',solution:'Each teammate should: (1) Acknowledge receipt of the broadcast to the lead. (2) Assess their in-progress work against the new constraint. (3) If their output-so-far exceeds 200 words, begin trimming or restructuring before completion. (4) If already past the point where trimming is possible without redoing work, report the conflict to the lead: "Acknowledged constraint. Current draft is 450 words. I can trim to 200 on completion, or restart now — which do you prefer?" The lead makes the call; the teammate does not decide unilaterally.'},{id:"bc-3",difficulty:"advanced",question:"Design a broadcast protocol that guarantees all team members have acknowledged and acted on a critical broadcast before the team lead proceeds. Include: message structure, acknowledgement schema, and what the lead does if a member fails to acknowledge within the timeout.",hint:"Think about this as a two-phase commit: announce, then confirm.",solution:'Phase 1 — Announce: Lead broadcasts { type: "broadcast", broadcast_id: UUID, criticality: "required_ack", content: {...}, ack_deadline: timestamp }. Phase 2 — Acknowledge: each teammate sends { type: "broadcast_ack", broadcast_id: UUID, agent_id: string, status: "received_and_applied" | "received_conflict", conflict_details: string | null }. Lead tracks acks by broadcast_id. If all acks arrive before deadline: proceed. If one or more agents fail to ack by deadline: lead queries their status directly (point-to-point). If no response to status query within secondary timeout: treat as failed, remove from active roster, reassign their task, proceed with remaining team. All ack state is logged for audit.'}]})]})}const S=Object.freeze(Object.defineProperty({__proto__:null,default:u},Symbol.toStringTag,{value:"Module"}));function m(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Async Mailboxes"}),e.jsx("p",{children:`Synchronous communication requires both agents to be "present" at the same time — the sender sends and waits, the recipient processes immediately and responds. This is simple but constraining: agents are blocked while waiting for responses, and the team's throughput is limited by its slowest synchronous exchange. Asynchronous mailboxes break this constraint.`}),e.jsx(t,{title:"Async Mailboxes",number:"Concept 8.7",children:"An async mailbox is a queue assigned to each agent into which other agents can deposit messages without waiting for an immediate response. The receiving agent processes messages from its mailbox whenever it is ready, not necessarily when the message was sent. This decouples senders from receivers: the sender continues working after depositing a message, and the receiver works through its queue at its own pace. Async mailboxes are the foundation of high-throughput team architectures."}),e.jsx("p",{children:"The trade-off is complexity: with async communication, the sender cannot assume the message has been received or processed by the time it takes its next action. It must design for the possibility that the recipient has not yet seen the message. This requires explicit acknowledgement mechanisms, careful sequencing of dependent actions, and timeouts for messages that remain unprocessed for too long."}),e.jsx(n,{title:"The Office Inbox",children:"The physical inbox on a desk is an async mailbox. Colleagues can leave documents while you are busy — they do not need to wait for you to read them immediately. You process your inbox when you reach a natural break in your current work. This is efficient for both parties. But it means you might not see an urgent message for an hour. Urgent communications require a different channel — a knock on the door — precisely because async communication cannot guarantee timely delivery for critical messages."}),e.jsx(s,{type:"tip",title:"Priority Lanes",children:"Design mailboxes with at least two priority lanes: standard and urgent. Agents check urgent messages before processing standard ones. Critical broadcasts, cancellation signals, and blocker notifications should use the urgent lane. Routine result deliveries and status updates use the standard lane. This simple prioritisation prevents urgent signals from being delayed behind a backlog of routine messages."}),e.jsx(a,{title:"Designing Async Mailbox Systems",exercises:[{id:"am-1",difficulty:"beginner",question:"What are two advantages of async mailboxes over synchronous communication in an agent team? What is one significant disadvantage that must be designed around?",hint:"Think about throughput, blocking, and the ordering guarantee you lose.",solution:"Advantages: (1) Higher throughput — senders never block waiting for recipients, so the whole team can progress simultaneously. (2) Resilience to speed mismatches — a slow agent does not stall a fast one. Disadvantage: no delivery guarantee without explicit acknowledgement — the sender cannot assume the recipient has acted on the message by any particular time. This must be handled with ack protocols, timeouts, and retry logic."},{id:"am-2",difficulty:"intermediate",question:"An agent sends an important task assignment via async mailbox and then, five minutes later, sends a follow-up that depends on the recipient having received and started the first message. What can go wrong, and how should the sender design around it?",hint:"Think about what the sender cannot safely assume about the recipient's mailbox state.",solution:"What can go wrong: the recipient may not have processed the first message yet when the follow-up arrives. The follow-up references a task the recipient hasn't seen. Processing the follow-up first produces confusion or failure. Design solution: (1) Include a prerequisite_message_id field in the follow-up — the recipient only processes it after confirming it has processed the referenced prior message. (2) Alternatively, the sender waits for an explicit ack of the first message before sending the follow-up (hybrid sync checkpoint). (3) Or bundle both messages into a single sequential message so the recipient processes them in order atomically."},{id:"am-3",difficulty:"advanced",question:"Design a dead-letter protocol for messages that remain unprocessed in a mailbox for longer than a threshold time. What should happen to the message, who should be notified, and how should the team recover?",hint:"Think about triage: is the recipient alive? Is the message still relevant?",solution:"Dead-letter protocol: (1) A watchdog monitors mailbox queue depths. When a message exceeds the age threshold, it is moved to a dead-letter queue. (2) The watchdog notifies the team lead with: { message_id, intended_recipient, age, message_type }. (3) The lead performs triage: (a) Is the recipient still active? If not, reassign the task to another agent or a new instance. (b) Is the message still relevant? If the task is complete via another path, discard. If still needed, re-deliver. (4) The lead records the incident in the audit log with its resolution action. (5) Persistent dead-lettering by the same recipient triggers a health-check and possible replacement."}]})]})}const P=Object.freeze(Object.defineProperty({__proto__:null,default:m},Symbol.toStringTag,{value:"Module"}));function p(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Approval Flows"}),e.jsx("p",{children:"Some agent actions are consequential enough that they should not proceed without explicit authorisation — from the team lead, from a human supervisor, or from a defined approval authority. Approval flows are the communication patterns that implement this gate. They are not a sign of distrust in the agent; they are a deliberate architectural choice to route certain classes of decision through a checkpoint before execution."}),e.jsx(t,{title:"Approval Flows",number:"Concept 8.8",children:"An approval flow is a communication pattern in which an agent pauses before a consequential action and sends an approval request to a designated authority — another agent, the team lead, or a human. Execution only proceeds when an explicit approval signal is received. Approval flows introduce latency deliberately in exchange for a safety guarantee: irreversible or high-impact actions do not happen autonomously."}),e.jsx("p",{children:"The decision of which actions require approval is a policy decision, not a technical one. It should be made based on the reversibility of the action, the cost of an incorrect decision, and the stakes of the domain. A researcher fetching a web page needs no approval. An executor that is about to delete a database table or send an email to ten thousand customers must pause and ask. The approval threshold defines where autonomous action ends and human (or lead) oversight begins."}),e.jsx(i,{title:"Define Approval Thresholds Explicitly",number:"Principle 8.3",children:"Every team should have a documented approval policy: a list of action categories and their required approval level (none, lead approval, human approval). Leaving approval thresholds implicit — trusting agents to judge for themselves which actions are consequential — is unreliable. The policy should be specified at team design time and encoded in each agent's constraints."}),e.jsx(s,{type:"note",title:"Approval vs Escalation",children:"Approval flows are pre-action gates: the agent asks before acting. Escalation is post-discovery: the agent acts as far as it safely can, then escalates when it hits a limit it cannot resolve. Both are valuable; they serve different purposes. Approval flows prevent unauthorised consequential actions; escalation handles novel situations the agent is not equipped to resolve unilaterally."}),e.jsx(a,{title:"Designing Approval Flows",exercises:[{id:"af-1",difficulty:"beginner",question:"For each of the following actions, decide whether no approval, lead approval, or human approval is appropriate: (a) reading a file; (b) sending an email to one user; (c) deleting a production database table; (d) updating a user's billing plan.",hint:"Consider reversibility and blast radius.",solution:"(a) Reading a file: no approval needed — read-only, no side effects. (b) Sending an email to one user: lead approval recommended — direct user contact has reputational risk but limited blast radius. (c) Deleting a production database table: human approval required — irreversible, potentially catastrophic. (d) Updating a billing plan: human approval required — financial impact, irreversible changes to a user account."},{id:"af-2",difficulty:"intermediate",question:"Design the message schema for an approval request and an approval response. What information must the request contain for the approver to make an informed decision quickly? What must the response contain for the requestor to act correctly?",hint:"Think about what context the approver needs and what execution parameters the response must confirm.",solution:'Approval request: { type: "approval_request", request_id: UUID, agent_id: string, action_type: string, action_description: string, affected_resources: string[], reversibility: "irreversible"|"recoverable"|"reversible", estimated_impact: string, context_summary: string, deadline_for_response: ISO-8601 }. Approval response: { type: "approval_response", request_id: UUID, decision: "approved"|"denied"|"deferred", approver_id: string, decided_at: ISO-8601, conditions: string | null, reason: string | null }. The agent only proceeds on "approved"; on "denied" it stops; on "deferred" it waits for a subsequent response.'},{id:"af-3",difficulty:"advanced",question:"An agent sends an approval request to a human approver but receives no response within the timeout. The action it was seeking approval for is time-sensitive — the window to act closes soon. Design the escalation path for this scenario.",hint:"Consider retry, re-routing to an alternative approver, and graceful degradation.",solution:'Escalation path: (1) At 50% of timeout: send a reminder to the primary approver (point-to-point, urgent priority). (2) At 80% of timeout: simultaneously notify the backup approver (if defined in policy) and the team lead. (3) At timeout expiry: if no response, the agent must not proceed with the consequential action. It reports to the team lead: { status: "approval_timeout", action_blocked: [...], time_window_closes_at: timestamp }. (4) Team lead decides: escalate to a human supervisor immediately, or accept the action is missed. (5) Audit log records: approval requested, reminders sent, timeout occurred, action blocked. This preserves the safety guarantee — no approved-action skipping even under time pressure.'}]})]})}const D=Object.freeze(Object.defineProperty({__proto__:null,default:p},Symbol.toStringTag,{value:"Module"}));function g(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Shutdown Protocols"}),e.jsx("p",{children:"A team that starts well but shuts down badly is still a broken team. Shutdown is the moment when the most resources can be wasted, the most side effects can be accidentally triggered, and the most state can be lost. A well-designed shutdown protocol is not an afterthought — it is a first-class design requirement that must be specified before the team is deployed."}),e.jsx(t,{title:"Shutdown Protocols",number:"Concept 8.9",children:"A shutdown protocol is the agreed sequence of communication and actions that brings a team to a clean, complete stop. It defines: who initiates shutdown (the lead, a human, an external signal), what each agent must do in response, how in-progress work is handled, and how the team confirms all members have reached a terminal state. A protocol that does not address all four elements leaves gaps that cause resource leaks, incomplete actions, or data loss."}),e.jsx("p",{children:"Shutdown is not always planned. A team may need to stop due to task completion (normal shutdown), user cancellation (requested shutdown), a critical error (emergency shutdown), or resource exhaustion (forced shutdown). Each scenario has different urgency and different acceptable trade-offs between clean shutdown and speed. The protocol must handle all four, even if the normal path is the most common."}),e.jsx(i,{title:"Shutdown Must Be Deterministic",number:"Principle 8.4",children:"A shutdown protocol should always produce the same outcome regardless of when it is triggered: all agents reach a terminal state, all external resources are released, and the team's final status is logged. Shutdown sequences that depend on race conditions, unacknowledged messages, or agent availability produce unpredictable results. Design shutdown to be deterministic: every agent must have a path to terminal state even if every other agent has already stopped."}),e.jsx(o,{title:"The Mid-Action Shutdown",children:"The hardest shutdown case is when an agent is mid-action at the moment shutdown is triggered — it has started a tool call that has real-world effects (sending a request, writing a record) but has not yet completed it. The agent cannot safely abandon the action (partial writes are often worse than completed or not-started writes), and it cannot safely continue (the team is shutting down. Design actions to be atomic where possible, and design shutdown signals to be acknowledged rather than immediate interrupts."}),e.jsx(a,{title:"Designing Shutdown Protocols",exercises:[{id:"sp-1",difficulty:"beginner",question:"What are the four types of shutdown a team may need to handle? For each, describe the key difference in how the team should respond compared to normal task completion.",hint:"Think about the initiator, the urgency, and the acceptable trade-offs in each case.",solution:"(1) Normal shutdown (task complete): orderly, all steps executed, results persisted, clean ledger update. (2) Requested shutdown (user cancels): similar to normal but partial results should be preserved; agents finish safe stopping points rather than task completion. (3) Emergency shutdown (critical error): faster than requested; agents may abort in-progress work to prevent further damage; all external connections closed immediately. (4) Forced shutdown (resource exhaustion or timeout): the infrastructure-level kill signal; agents may not reach their own shutdown logic; external resource release must be handled by the infrastructure layer, not the agent."},{id:"sp-2",difficulty:"intermediate",question:"Design the message exchange for a requested shutdown initiated by the team lead. Include: the shutdown signal, agent acknowledgement, partial-result submission, and final confirmation.",hint:"Think of it as a four-step handshake.",solution:'Step 1 — Lead broadcasts shutdown signal: { type: "shutdown_request", shutdown_id: UUID, mode: "graceful", reason: "user_cancellation", complete_current_action: true, deadline: timestamp }. Step 2 — Each agent sends: { type: "shutdown_ack", shutdown_id: UUID, agent_id: string, status: "acknowledged", current_action: "completing"|"none" }. Step 3 — Each agent sends, when ready: { type: "shutdown_ready", shutdown_id: UUID, agent_id: string, partial_results: object|null, resources_released: bool }. Step 4 — Lead confirms all agents in terminal state: { type: "shutdown_complete", shutdown_id: UUID, agents_terminated: [...], partial_results_stored: bool }.'},{id:"sp-3",difficulty:"advanced",question:"An agent receives a shutdown signal while it is waiting for a response from an external API. The API call has already been sent and cannot be cancelled. The agent holds a database row lock that must be released. What should the agent do?",hint:"Prioritise resource release over result collection; differentiate between blocking and non-blocking resource holds.",solution:'The agent should: (1) Acknowledge the shutdown signal immediately to prevent the lead from timing out waiting for it. (2) Release the database row lock right now — holding a lock through shutdown is a guaranteed resource leak. The lock can be released without waiting for the API response. (3) Set a short timeout for the API response (e.g., 10 seconds). If the response arrives within the window, record it in the partial-results package. If not, log "API response pending at shutdown" and proceed. (4) Under no circumstances wait indefinitely for the API response — the agent must reach terminal state by the shutdown deadline regardless. (5) Send shutdown_ready with whatever partial result is available and resources_released: true.'}]})]})}const C=Object.freeze(Object.defineProperty({__proto__:null,default:g},Symbol.toStringTag,{value:"Module"}));function f(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"What Is a Swarm?"}),e.jsx("p",{children:"A team has defined roles, structured communication, and a lead that coordinates the whole. A swarm is something different: a large collection of agents that work on the same problem without central coordination, each processing a piece of the work independently and contributing to a shared result. Swarms trade structure for scale."}),e.jsx(t,{title:"Agent Swarm",number:"Concept 8.10",children:"An agent swarm is a collection of many homogeneous agents executing the same class of task across different inputs simultaneously, without direct coordination between individuals. Swarms are appropriate for embarrassingly parallel problems: tasks that can be divided into independent units where no unit depends on another. A swarm's power is sheer throughput — hundreds of agents processing in parallel can complete in minutes what a sequential agent would take hours to finish."}),e.jsx("p",{children:"The defining characteristic of a swarm is independence between workers. This is both a capability and a constraint. Because workers don't coordinate, they don't block each other — which is where the speed advantage comes from. But they also cannot share intermediate results, cannot adapt their work based on what other workers found, and cannot handle tasks where the order of operations matters. Swarms are not a general-purpose architecture; they are a specific tool for a specific class of problem."}),e.jsx(n,{title:"The Document Review Farm",children:"A law firm reviewing a hundred thousand documents in discovery uses a review farm: dozens of lawyers working in parallel, each assigned a batch of documents, each using the same criteria. They don't coordinate with each other — they simply apply the same process to their assigned batch and submit their findings to the lead attorney. The lead collects everything, not individual workers. This is a human swarm: parallel, homogeneous, and independent."}),e.jsx(s,{type:"intuition",title:"Swarm vs Team Decision",children:"When you find yourself wanting to add dozens of agents, ask: are the tasks truly independent? If yes, you want a swarm. If the tasks have dependencies — if the output of one agent shapes what another should do — you want a team. Confusing the two patterns results in either a swarm of dependent agents (uncoordinated chaos) or a team of independent workers (unnecessary coordination overhead)."}),e.jsx(a,{title:"Understanding Agent Swarms",exercises:[{id:"ws-1",difficulty:"beginner",question:'List three tasks that are well-suited for a swarm architecture and three that are not. For each "not suited" task, explain which swarm characteristic it violates.',hint:"Focus on task independence as the key criterion.",solution:"Well-suited: (1) Transcribing 1,000 audio clips — each clip is independent. (2) Classifying 50,000 images — each image is independent. (3) Translating 200 product descriptions — each description is independent. Not suited: (1) Writing a novel — chapters depend on each other, characters must be consistent across agents. Violates independence. (2) Multi-step reasoning across a shared dataset — later steps depend on earlier findings. Violates independence. (3) Building a software system — components must integrate; design decisions in one component affect others. Violates independence."},{id:"ws-2",difficulty:"intermediate",question:"A swarm of 50 agents is processing customer feedback from 50,000 records. Halfway through, the classification criteria change. How does a swarm handle this compared to how a team would?",hint:"Think about the broadcast mechanism for swarms and the consistency challenge.",solution:"In a swarm, there is no internal coordination mechanism — the only way to update criteria is to broadcast the change from the swarm controller. Records already processed under the old criteria must be reprocessed, creating a consistency problem: some results use old criteria, some new. The swarm cannot self-correct. In a team, the lead broadcasts the change to all teammates, each acknowledges and applies it going forward. Already-completed work is flagged for review. The team can coordinate a consistent response; the swarm simply continues, producing an inconsistent output set."},{id:"ws-3",difficulty:"advanced",question:"Design a partitioning strategy for a swarm of 20 agents processing 10,000 items, accounting for: unequal processing times per item, agent failures during the run, and the need to ensure every item is processed exactly once.",hint:"Think about dynamic work queues rather than static pre-assignment.",solution:`Use a central work queue rather than pre-assignment: (1) Items are loaded into a queue, each marked "available". (2) Each agent pulls items from the queue one at a time by claiming them (marking them "in-progress" with the claiming agent's ID and a lease expiry). (3) The lease expiry handles agent failures: if an agent fails mid-item, its claimed item's lease expires and the item returns to "available" for another agent to claim. (4) On completion, the agent marks the item "done". (5) A controller monitors for items stuck in "in-progress" past their lease and returns them to the queue. This guarantees exactly-once processing across failures and handles unequal times naturally — fast agents claim more items.`}]})]})}const W=Object.freeze(Object.defineProperty({__proto__:null,default:f},Symbol.toStringTag,{value:"Module"}));function w(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Execution Backends"}),e.jsx("p",{children:"A swarm of agents does not run on good intentions — it runs on infrastructure. The execution backend is the layer that actually instantiates agents, allocates resources, routes work, and terminates workers when done. Understanding the properties and trade-offs of different execution backends is essential for designing swarms that scale reliably."}),e.jsx(t,{title:"Execution Backend",number:"Concept 8.11",children:"An execution backend is the infrastructure layer responsible for spawning, running, and terminating agents in a multi-agent system. Backends vary along several dimensions: whether they are synchronous or asynchronous, whether agents run in the same process or different processes (or machines), how they handle failures, and what isolation guarantees they provide. The backend shapes what parallelism is achievable, what the failure model looks like, and how observable the running system is."}),e.jsx("p",{children:"Common backend patterns include in-process thread pools (fast, low overhead, shared memory — useful for lightweight swarms), distributed task queues (high throughput, fault-tolerant, isolated — useful for large-scale swarms), and serverless invocation (infinite scale on demand, stateless — useful for burst workloads). The choice depends on the scale of parallelism, the duration of individual tasks, the need for isolation, and the acceptable cost of coordination overhead."}),e.jsx(s,{type:"note",title:"Observability as a Backend Requirement",children:"Every production execution backend must provide observability: the ability to see, in real time, how many agents are running, what each is doing, and how many have completed or failed. Without observability, a swarm in production is a black box. When something goes wrong, there is no way to tell what happened, which items were processed, or where work was lost. Treat observability as a first-class backend requirement."}),e.jsx(i,{title:"Match the Backend to the Workload",number:"Principle 8.5",children:"An in-process thread pool is wasteful for 10,000-agent swarms; a distributed task queue is over-engineered for a ten-agent team. Match the execution backend to the scale and characteristics of the actual workload. Start with the simplest backend that meets requirements; migrate to more complex infrastructure only when the simpler option provably cannot scale to the required load."}),e.jsx(a,{title:"Choosing and Designing Execution Backends",exercises:[{id:"eb-1",difficulty:"beginner",question:"For each scenario, identify which execution backend pattern (in-process thread pool, distributed task queue, or serverless) is most appropriate and explain why: (a) classify 100 images in a web server request; (b) process 1 million log entries overnight; (c) run 10 coordinated research agents for a single user session.",hint:"Consider scale, duration, and the need for coordination.",solution:"(a) In-process thread pool: small scale (100 items), needs to complete within a request, no persistent coordination needed. (b) Distributed task queue: massive scale (1M items), fault tolerance important for overnight runs, items are independent. (c) In-process or lightweight distributed pool: small team (10 agents), coordination is needed within the session, serverless would add too much cold-start latency for interactive use."},{id:"eb-2",difficulty:"intermediate",question:"A swarm of 200 agents is processing work using a distributed task queue. The queue has 5,000 items. Halfway through, the backend reports that 30 agents have crashed. How should the system respond, and what backend features make this recovery possible?",hint:"Think about item leasing, automatic retry, and how the queue re-exposes crashed work.",solution:`Recovery process: (1) The 30 crashed agents' claimed items have their leases expire automatically. The queue re-exposes these items as "available". (2) The remaining 170 agents continue pulling from the queue, picking up the re-exposed items alongside new ones. (3) If 30 new agent instances are available (via auto-scaling), they are added to the pool and begin pulling work immediately. (4) No items are lost because the queue held the canonical state; agent crashes only affect in-progress items, which are automatically retried. Backend features required: item leasing with expiry, automatic failure detection, visibility into queue depth and agent count.`},{id:"eb-3",difficulty:"advanced",question:'Design the observability surface for a swarm execution backend. Define what metrics should be tracked in real time, what alerts should trigger, and what a runbook entry for "swarm significantly underperforming" should look like.',hint:"Think about throughput, error rate, queue depth, and agent health as core signal categories.",solution:"Real-time metrics: (1) Queue depth (items available, in-progress, completed, failed). (2) Agent count (active, crashed, idle). (3) Throughput (items completed per minute). (4) Error rate (failed items / total claimed). (5) Tail latency (P95, P99 processing time per item). (6) Lease expiry rate (proxy for agent instability). Alerts: queue depth not decreasing after 5 minutes (swarm stalled), error rate > 5% (systematic failure), active agent count drops by > 20% in 1 minute (agent crash wave). Runbook for underperformance: (1) Check active agent count — if low, check for crash wave and re-provision. (2) Check individual agent logs — are agents taking longer per item than expected? (3) Check external dependencies — is a shared API rate-limiting? (4) Check queue for stuck items with expired leases — requeue if needed. (5) If throughput remains low after addressing the above, scale up agent count."}]})]})}const M=Object.freeze(Object.defineProperty({__proto__:null,default:w},Symbol.toStringTag,{value:"Module"}));function y(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Identity and Visibility"}),e.jsx("p",{children:"When a single agent operates alone, there is no question about who did what. In a swarm, that clarity vanishes. Multiple agents work simultaneously, produce outputs, consume resources, and sometimes fail. Without a deliberate system for identity and visibility, debugging a swarm is like investigating a crime where every witness is anonymous."}),e.jsx(t,{title:"Agent Identity",number:"8.11",children:e.jsx("p",{children:"Agent identity is a unique, persistent label attached to every agent instance in a swarm. Identity includes a name or identifier, a role description, and metadata about when and why the agent was created. Identity serves two purposes: it allows operators to distinguish one agent from another in logs and dashboards, and it allows agents themselves to reference each other when coordinating work."})}),e.jsx(n,{title:"Name Badges at a Conference",children:e.jsx("p",{children:"Imagine a conference where nobody wears a name badge. You overhear interesting conversations but cannot tell who said what, who to follow up with, or who is responsible for a particular session. Name badges solve this — a glance tells you who someone is and what organization they represent. Agent identity serves the same function: it makes the swarm legible to the people operating it."})}),e.jsx("p",{children:"Visibility goes beyond identity. It means being able to observe, in real time or after the fact, what each identified agent is doing. This includes what task it is working on, what stage it has reached, what resources it has consumed, and whether it has encountered errors. Visibility turns a swarm from an opaque process into a transparent one."}),e.jsx(i,{title:"Every Agent Action Must Be Attributable",number:"8.6",children:e.jsx("p",{children:'No output, log entry, or side effect should exist without a clear trail back to the specific agent that produced it. Attribution is not optional instrumentation — it is a design requirement. When something goes wrong, the first question is always "which agent did this?" If the answer is "we cannot tell," the system is not production-ready.'})}),e.jsx(s,{title:"Color-coding and visual distinction",type:"tip",children:e.jsx("p",{children:"In dashboards and monitoring tools, assigning distinct visual markers — colors, icons, or position — to different agent roles dramatically improves an operator's ability to scan and understand swarm behavior at a glance. Human perception is fast at distinguishing color; use that to your advantage."})}),e.jsx(a,{title:"Exercises",exercises:[{id:"iv-1",difficulty:"beginner",question:"A swarm of 20 agents processes customer support tickets. After a run, three tickets have incorrect responses. How does agent identity help you diagnose the problem? What information should each agent's identity record include?",hint:"Think about what you would need to trace the bad outputs back to their source.",solution:"Agent identity lets you look up which specific agent handled each of the three problematic tickets. Each identity record should include: a unique agent ID, the role or specialization assigned, the timestamp of creation, and a log of task assignments. With this, you can check whether all three bad responses came from the same agent (indicating a single faulty agent) or from different agents (indicating a systemic issue). Without identity, you would have no way to distinguish these two very different failure modes."},{id:"iv-2",difficulty:"intermediate",question:"Design a naming convention for agents in a swarm that processes documents through three stages: extraction, analysis, and summarization. The swarm may have multiple agents at each stage. What should the names encode, and why?",hint:"Consider encoding the role, the instance number, and the run identifier into the name.",solution:'A good naming convention encodes role, instance, and run: for example, "extract-03-run-20240115a" tells you the agent does extraction, is the third instance of that role, and belongs to a specific run. This convention lets operators filter logs by role (show all extractors), by instance (show one specific agent), or by run (show everything from one execution). Avoid purely random identifiers — they are unique but convey no information at a glance. The name should be both machine-parseable and human-readable.'},{id:"iv-3",difficulty:"advanced",question:'A swarm has 200 agents and an operator reports that "the system feels slow." Design a visibility dashboard that lets the operator quickly identify whether the slowness is caused by a few underperforming agents, a bottleneck at one stage, or a systemic resource issue.',hint:"Think about what aggregate views and drill-down capabilities would answer each of these three hypotheses.",solution:"The dashboard needs three views. (1) Agent heatmap: a grid of all 200 agents color-coded by current throughput (items per minute). A few red squares among green ones indicates isolated underperformers. (2) Stage throughput chart: a bar chart showing throughput at each pipeline stage. If one stage is dramatically lower than others, that is the bottleneck. (3) Resource utilization panel: CPU, memory, and API rate limit usage across the system. If all agents show high resource pressure, the issue is systemic. The operator starts at the highest level (overall throughput), then drills into the view that matches the pattern they see. Each agent in every view is clickable, linking to its identity record and detailed log."}]})]})}const E=Object.freeze(Object.defineProperty({__proto__:null,default:y},Symbol.toStringTag,{value:"Module"}));function b(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Shared State"}),e.jsx("p",{children:"Agents in a swarm rarely work in complete isolation. They need to know what others have done, what remains to be done, and what the current state of the overall task looks like. Shared state is the mechanism that makes this coordination possible — a common pool of information that all agents can read from and write to."}),e.jsx(t,{title:"Shared State",number:"8.12",children:e.jsx("p",{children:"Shared state is any data structure, store, or communication channel that multiple agents in a swarm can access to coordinate their behavior. It includes task queues, progress trackers, result stores, and coordination flags. The design of shared state determines how efficiently agents can divide work, avoid duplication, and combine results."})}),e.jsx(n,{title:"The Shared Whiteboard",children:e.jsx("p",{children:"Picture a team of researchers in a room with a large whiteboard. Each person works independently but walks to the whiteboard to check what others have found, mark their own progress, and claim the next unclaimed topic. The whiteboard is the shared state — it does not do the research, but without it the team would constantly duplicate work or miss critical findings. The whiteboard's layout and conventions determine how smoothly the team operates."})}),e.jsx("p",{children:"The fundamental tension in shared state design is between accessibility and consistency. Making state easy to read and write encourages coordination, but concurrent access creates the risk of stale reads, lost updates, and race conditions. Every shared state design must decide how to balance these forces."}),e.jsx(i,{title:"Minimize Shared State Surface",number:"8.7",children:e.jsx("p",{children:"Share only what agents need to coordinate — not everything they know. The more state that is shared, the more opportunities for contention, inconsistency, and coupling between agents. Each piece of shared state should justify its existence by enabling coordination that would otherwise be impossible. Private state should remain private."})}),e.jsx(o,{title:"Stale reads cause silent failures",children:e.jsx("p",{children:'When an agent reads shared state and acts on it, the state may have changed by the time the action completes. Two agents can both read "task X is unclaimed," both claim it, and both do the work. Without mechanisms like atomic claims or optimistic locking, these silent duplications accumulate and waste resources without any error being raised.'})}),e.jsx(a,{title:"Exercises",exercises:[{id:"ss-1",difficulty:"beginner",question:"A swarm of five agents must process a list of 100 items without any agent working on the same item as another. What shared state do they need, and what is the minimum information it must contain?",hint:"Think about what each agent needs to know before picking up the next item.",solution:"The minimum shared state is a task registry that tracks, for each item, whether it is unclaimed, in-progress (and by which agent), or completed. Each agent checks the registry, atomically claims an unclaimed item, processes it, and marks it complete. The registry needs only three fields per item: item ID, status, and claiming agent ID. This is the minimum — anything less leads to duplicate work or missed items."},{id:"ss-2",difficulty:"intermediate",question:"Two swarm architectures are proposed: (A) agents share a single global results dictionary where each writes its findings, and (B) each agent writes to its own private results store, with a final aggregation step. What are the trade-offs between these two approaches?",hint:"Consider write contention, failure isolation, and the complexity of the aggregation step.",solution:"Architecture A (shared dictionary): simpler final output (already aggregated), but creates write contention as agents compete to update the same structure. A single agent's crash while writing can corrupt shared state. Architecture B (private stores + aggregation): eliminates write contention entirely since agents never compete for the same resource. A crash affects only one agent's private store. The trade-off is that aggregation must be designed separately, and intermediate progress is harder to observe since results are scattered. For most swarms, B is safer — the aggregation step is a small price for eliminating contention."},{id:"ss-3",difficulty:"advanced",question:"Design the shared state architecture for a swarm where agents must not only avoid duplicate work but also build on each other's partial results. For instance, agent A discovers a fact that changes how agent B should process its item. How do you structure this interdependency without creating a bottleneck?",hint:"Think about publish-subscribe patterns and event-driven updates rather than polling.",solution:"Use a two-layer shared state architecture. Layer 1: a task queue with atomic claims (same as simple swarms, handles work distribution). Layer 2: an event bus where agents publish discoveries as typed events. Agents subscribe to event types relevant to their current task. When agent A discovers a fact, it publishes an event. Agent B, if subscribed to that event type, receives it and can adjust its processing. This avoids bottlenecks because: the event bus is append-only (no contention), agents filter events locally (no central processing), and the task queue and event bus are independent systems. The key design choice is making events immutable and typed — agents decide locally what is relevant, rather than a central coordinator pushing updates."}]})]})}const B=Object.freeze(Object.defineProperty({__proto__:null,default:b},Symbol.toStringTag,{value:"Module"}));function v(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Conflict Resolution"}),e.jsx("p",{children:"Whenever multiple agents can act on the same resource, modify the same output, or reach different conclusions about the same question, conflict is inevitable. Conflict resolution is not an edge case to handle later — it is a core design concern that must be addressed before a swarm is deployed."}),e.jsx(t,{title:"Conflict Resolution",number:"8.13",children:e.jsx("p",{children:"Conflict resolution is the set of rules and mechanisms a multi-agent system uses to handle situations where agents produce incompatible outputs, claim overlapping resources, or reach contradictory conclusions. Resolution strategies range from simple (last write wins) to sophisticated (voting, arbitration by a designated authority, or structured merge). The right strategy depends on the cost of an incorrect resolution."})}),e.jsx(n,{title:"Two Editors, One Document",children:e.jsx("p",{children:"Imagine two editors revising the same paragraph of a manuscript simultaneously. One tightens the prose, the other restructures the argument. When they compare their versions, the changes are incompatible — you cannot simply overlay one on the other. Someone must decide which revision to keep, how to merge them, or whether to start fresh. Multi-agent conflicts follow the same pattern: independent work produces divergent results that require deliberate reconciliation."})}),e.jsx("p",{children:"The simplest conflicts are resource conflicts — two agents trying to claim the same task. These are resolved mechanically through atomic operations. More complex are output conflicts, where agents produce different results for the same question. The hardest are strategy conflicts, where agents disagree about what approach to take. Each level requires different resolution mechanisms."}),e.jsx(i,{title:"Define Conflict Resolution Before Conflicts Occur",number:"8.8",children:e.jsx("p",{children:"Every shared resource and every point where agent outputs converge must have a pre-defined conflict resolution policy. Discovering that you need conflict resolution during a production run means the conflict has already caused damage. Anticipate where conflicts can arise and encode the resolution strategy into the system design from the beginning."})}),e.jsx(o,{title:"Last-write-wins destroys information",children:e.jsx("p",{children:"The simplest resolution strategy — accepting whichever result was written last — is also the most dangerous. It silently discards the earlier result without evaluating whether it was better. In agent systems where outputs carry different levels of confidence or quality, last-write-wins can consistently discard the superior result in favor of the merely more recent one."})}),e.jsx(a,{title:"Exercises",exercises:[{id:"cr-1",difficulty:"beginner",question:'Three agents are asked to classify the same document. Agent A says "urgent," Agent B says "routine," and Agent C says "urgent." How should the system resolve this disagreement? What if the vote were 2-1 in the other direction?',hint:"Consider majority voting and whether all agents' opinions should carry equal weight.",solution:'With simple majority voting, the document is classified as "urgent" (2-1). If the vote were 2-1 for "routine," the classification would be "routine." Majority voting works when agents have roughly equal competence and the classification is discrete. However, if Agent A is known to be more accurate for this document type, a weighted voting system might override the majority. The key insight is that majority voting is a reasonable default, but equal weighting assumes equal competence — an assumption worth verifying.'},{id:"cr-2",difficulty:"intermediate",question:"Two agents are refactoring different parts of a codebase and both modify a shared configuration file. Their changes are logically independent but textually overlap. Design a resolution strategy that does not require human intervention.",hint:"Think about how version control systems handle this, and what additional context agents have that text-based merge tools do not.",solution:`Use a semantic merge strategy: instead of merging text, have each agent express its changes as structured operations (e.g., "set key X to value Y," "add entry Z to list W"). A merge coordinator applies all non-conflicting operations directly. For true conflicts (both agents modify the same key to different values), the coordinator uses a priority rule based on which agent's task has higher relevance to that key. If priority is equal, the coordinator spawns a brief arbitration step: a single agent reviews both proposed values with the context of why each was chosen, and selects or synthesizes the final value. This is automatic because the arbitration agent has access to both agents' reasoning.`},{id:"cr-3",difficulty:"advanced",question:"Design a conflict resolution framework for a swarm where agents may disagree not just on outputs but on strategy — for example, one agent believes the task should be decomposed differently than another. How do you resolve strategic disagreements without a single point of authority becoming a bottleneck?",hint:"Consider time-boxed experimentation, where competing strategies run in parallel briefly and results determine the winner.",solution:"Use a competitive evaluation pattern. When a strategic disagreement is detected: (1) Each competing strategy is allocated a small, equal budget (time or resources) to demonstrate results on a subset of the work. (2) An evaluation function — defined before the conflict, not ad hoc — measures the quality and efficiency of each strategy's partial results. (3) The strategy with better evaluation results is adopted for the remainder of the work. (4) If results are statistically indistinguishable, the system defaults to the simpler strategy (fewer coordination requirements). This avoids a single authority bottleneck because the resolution is empirical, not authoritative. The evaluation function is the pre-defined policy; no agent or coordinator makes a subjective judgment. The cost is the parallel experimentation budget, which must be bounded to prevent strategic disagreements from consuming too many resources."}]})]})}const O=Object.freeze(Object.defineProperty({__proto__:null,default:v},Symbol.toStringTag,{value:"Module"}));export{j as a,q as b,A as c,_ as d,I as e,S as f,P as g,D as h,C as i,W as j,M as k,E as l,B as m,O as n,T as s};
